import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.Pywvta2k.js";const g=JSON.parse('{"title":"医易身心同调：阴阳两型辨证实战","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/06-普光普明医易辨证实战.md","filePath":"tcm-data/09-医易同源/06-普光普明医易辨证实战.md","lastUpdated":1781084559000}'),r={name:"tcm-data/09-医易同源/06-普光普明医易辨证实战.md"};function d(n,t,o,s,h,f){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="医易身心同调-阴阳两型辨证实战" tabindex="-1">医易身心同调：阴阳两型辨证实战 <a class="header-anchor" href="#医易身心同调-阴阳两型辨证实战" aria-label="Permalink to &quot;医易身心同调：阴阳两型辨证实战&quot;">​</a></h1><blockquote><p>本页将《周易》卦象体系与中医辨证结合，演示医易同调的辨证思维 使用对象：中医从业人员、中医爱好者</p></blockquote><hr><h2 id="一、医易辨证总纲" tabindex="-1">一、医易辨证总纲 <a class="header-anchor" href="#一、医易辨证总纲" aria-label="Permalink to &quot;一、医易辨证总纲&quot;">​</a></h2><h3 id="核心原则-观象→类象→取象→用象" tabindex="-1">核心原则：观象→类象→取象→用象 <a class="header-anchor" href="#核心原则-观象→类象→取象→用象" aria-label="Permalink to &quot;核心原则：观象→类象→取象→用象&quot;">​</a></h3><p>医易同源的本质在于&quot;象思维&quot;：</p><ol><li><strong>观象</strong>：观察患者呈现的症状之象（舌象、脉象、面色、体象）</li><li><strong>类象</strong>：将症状归入八卦/六十四卦体系</li><li><strong>取象</strong>：确定当前&quot;卦象&quot;所对应的病机</li><li><strong>用象</strong>：依据&quot;卦象&quot;选择对应的治理方向和方药</li></ol><hr><h2 id="二、两型通用模板" tabindex="-1">二、两型通用模板 <a class="header-anchor" href="#二、两型通用模板" aria-label="Permalink to &quot;二、两型通用模板&quot;">​</a></h2><h3 id="模板一-阳虚湿盛型-对应坤→复卦" tabindex="-1">模板一：阳虚湿盛型（对应坤→复卦） <a class="header-anchor" href="#模板一-阳虚湿盛型-对应坤→复卦" aria-label="Permalink to &quot;模板一：阳虚湿盛型（对应坤→复卦）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">年命</td><td style="text-align:left;">壬戌（水狗年）</td></tr><tr><td style="text-align:left;">体质卦象</td><td style="text-align:left;">坤为地 → 地雷复</td></tr><tr><td style="text-align:left;">核心病机</td><td style="text-align:left;">土湿水寒 → 水中寒极一阳来复</td></tr><tr><td style="text-align:left;">五行特征</td><td style="text-align:left;">水土过旺、火弱不生土</td></tr><tr><td style="text-align:left;">体质特点</td><td style="text-align:left;">脾肾阳虚、寒湿内盛</td></tr><tr><td style="text-align:left;">易感病</td><td style="text-align:left;">水肿、虚劳、眩晕、厥逆</td></tr></tbody></table><h4 id="体质调理卦序" tabindex="-1">体质调理卦序 <a class="header-anchor" href="#体质调理卦序" aria-label="Permalink to &quot;体质调理卦序&quot;">​</a></h4><p>复卦（一阳来复）→ 临卦（二阳渐长）→ 泰卦（三阳开泰）</p><h4 id="调治要点" tabindex="-1">调治要点 <a class="header-anchor" href="#调治要点" aria-label="Permalink to &quot;调治要点&quot;">​</a></h4><ul><li><strong>治则</strong>：温阳化湿，以坤土厚德载物</li><li><strong>饮食</strong>：温热为主，忌生冷寒凉</li><li><strong>运动</strong>：宜温和运动忌大汗</li><li><strong>时节</strong>：春夏养阳最佳，三伏天灸</li></ul><hr><h3 id="模板二-阴虚湿热型-对应离→未济卦" tabindex="-1">模板二：阴虚湿热型（对应离→未济卦） <a class="header-anchor" href="#模板二-阴虚湿热型-对应离→未济卦" aria-label="Permalink to &quot;模板二：阴虚湿热型（对应离→未济卦）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">年命</td><td style="text-align:left;">壬戌（水狗年）</td></tr><tr><td style="text-align:left;">体质卦象</td><td style="text-align:left;">离为火 → 火水未济</td></tr><tr><td style="text-align:left;">核心病机</td><td style="text-align:left;">阴虚火旺 → 水火不交 → 火在上而水在下</td></tr><tr><td style="text-align:left;">五行特征</td><td style="text-align:left;">水火不交、火有余而水不足</td></tr><tr><td style="text-align:left;">体质特点</td><td style="text-align:left;">阴虚内热、兼夹湿热</td></tr><tr><td style="text-align:left;">易感病</td><td style="text-align:left;">失眠、虚劳、经带病、消渴</td></tr></tbody></table><h4 id="体质调理卦序-1" tabindex="-1">体质调理卦序 <a class="header-anchor" href="#体质调理卦序-1" aria-label="Permalink to &quot;体质调理卦序&quot;">​</a></h4><p>未济卦（水火不交）→ 既济卦（水火既济）→ 泰卦（阴阳平衡）</p><h4 id="调治要点-1" tabindex="-1">调治要点 <a class="header-anchor" href="#调治要点-1" aria-label="Permalink to &quot;调治要点&quot;">​</a></h4><ul><li><strong>治则</strong>：滋阴降火，引火归元</li><li><strong>饮食</strong>：清淡滋阴，忌辛辣燥热</li><li><strong>运动</strong>：不宜大汗，宜静养太极</li><li><strong>时节</strong>：秋冬养阴最佳</li></ul><hr><h2 id="三、两型合参-家庭调理模板" tabindex="-1">三、两型合参：家庭调理模板 <a class="header-anchor" href="#三、两型合参-家庭调理模板" aria-label="Permalink to &quot;三、两型合参：家庭调理模板&quot;">​</a></h2><h3 id="阴阳同调的原理" tabindex="-1">阴阳同调的原理 <a class="header-anchor" href="#阴阳同调的原理" aria-label="Permalink to &quot;阴阳同调的原理&quot;">​</a></h3><p>同一生活环境中的不同个体，会呈现相反的体质倾向：</p><ul><li>阳虚型者需要温阳（补火）</li><li>阴虚型者需要滋阴（补水）</li><li>两者调理时当分途而治，不可套用同一方案</li></ul><h3 id="家庭饮食调理对照表" tabindex="-1">家庭饮食调理对照表 <a class="header-anchor" href="#家庭饮食调理对照表" aria-label="Permalink to &quot;家庭饮食调理对照表&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">宜食</th><th style="text-align:left;">忌食</th><th style="text-align:left;">推荐食谱</th></tr></thead><tbody><tr><td style="text-align:left;">阳虚湿盛型</td><td style="text-align:left;">羊肉、生姜、桂圆、山药</td><td style="text-align:left;">西瓜、苦瓜、绿茶</td><td style="text-align:left;">当归生姜羊肉汤</td></tr><tr><td style="text-align:left;">阴虚湿热型</td><td style="text-align:left;">银耳、百合、冬瓜、薏米</td><td style="text-align:left;">辣椒、羊肉、酒</td><td style="text-align:left;">冬瓜薏米排骨汤</td></tr></tbody></table><h3 id="家庭日常调护" tabindex="-1">家庭日常调护 <a class="header-anchor" href="#家庭日常调护" aria-label="Permalink to &quot;家庭日常调护&quot;">​</a></h3><ul><li>分餐调理：同一餐桌上不同类型者各吃适合自己的食物</li><li>季节调理：春夏侧重温阳、秋冬侧重滋阴</li><li>情绪调理：阳虚者宜振奋情绪，阴虚者宜静心安神</li></ul><hr><h2 id="四、常用药食同源对比" tabindex="-1">四、常用药食同源对比 <a class="header-anchor" href="#四、常用药食同源对比" aria-label="Permalink to &quot;四、常用药食同源对比&quot;">​</a></h2><h3 id="同一药材的不同用法" tabindex="-1">同一药材的不同用法 <a class="header-anchor" href="#同一药材的不同用法" aria-label="Permalink to &quot;同一药材的不同用法&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药材</th><th style="text-align:left;">阳虚型用法</th><th style="text-align:left;">阴虚型用法</th></tr></thead><tbody><tr><td style="text-align:left;">人参</td><td style="text-align:left;">温补阳气（红参/生晒参）</td><td style="text-align:left;">益气养阴（西洋参/太子参）</td></tr><tr><td style="text-align:left;">当归</td><td style="text-align:left;">补血温通（全当归）</td><td style="text-align:left;">养血润燥（当归身）</td></tr><tr><td style="text-align:left;">枸杞</td><td style="text-align:left;">温阳（用量稍大）</td><td style="text-align:left;">滋阴（用量适中）</td></tr><tr><td style="text-align:left;">肉桂</td><td style="text-align:left;">温阳散寒</td><td style="text-align:left;">引火归元（小量）</td></tr><tr><td style="text-align:left;">麦冬</td><td style="text-align:left;">少量（防滋腻）</td><td style="text-align:left;">适量（养阴为主）</td></tr></tbody></table><hr><h2 id="五、三因制宜原则" tabindex="-1">五、三因制宜原则 <a class="header-anchor" href="#五、三因制宜原则" aria-label="Permalink to &quot;五、三因制宜原则&quot;">​</a></h2><h3 id="因地-大理地区" tabindex="-1">因地（大理地区） <a class="header-anchor" href="#因地-大理地区" aria-label="Permalink to &quot;因地（大理地区）&quot;">​</a></h3><ul><li>高原低氧 → 气易虚</li><li>风大干燥 → 外燥内湿</li><li>早晚温差大 → 易感风寒</li><li>洱海水湿 → 外湿引动内湿</li></ul><h3 id="因时-当前节气" tabindex="-1">因时（当前节气） <a class="header-anchor" href="#因时-当前节气" aria-label="Permalink to &quot;因时（当前节气）&quot;">​</a></h3><ul><li>春生夏长：温阳最佳之际</li><li>长夏化湿：化湿黄金时间</li><li>秋收冬藏：养阴大好时机</li></ul><h3 id="因人" tabindex="-1">因人 <a class="header-anchor" href="#因人" aria-label="Permalink to &quot;因人&quot;">​</a></h3><ul><li>年龄因素：不同年龄段的不同调治重点</li><li>生活规律：作息、饮食、运动习惯的综合评估</li><li>情志因素：工作压力、家庭关系对体质的影响</li></ul><hr><p><em>本模板为通用辨证框架，具体临证请结合四诊合参。</em></p>',45)])])}const u=e(r,[["render",d]]);export{g as __pageData,u as default};
